import{_ as p,c as t,b as n,e as a,d as l,w as i,a as c,r as o,o as r}from"./app-DfFNXaa-.js";const d={};function u(k,s){const e=o("RouteLink");return r(),t("div",null,[s[3]||(s[3]=n("h1",{id:"postgresql-tid-store",tabindex:"-1"},[n("a",{class:"header-anchor",href:"#postgresql-tid-store"},[n("span",null,"PostgreSQL - Tid Store")])],-1)),s[4]||(s[4]=n("p",null,"Created by: Mr Dk.",-1)),s[5]||(s[5]=n("p",null,"Co-authored by: Claude Opus 4.6",-1)),s[6]||(s[6]=n("p",null,"2026 / 05 / 18 15:30",-1)),s[7]||(s[7]=n("p",null,"Hangzhou, Zhejiang, China",-1)),s[8]||(s[8]=n("hr",null,null,-1)),s[9]||(s[9]=n("h2",{id:"背景",tabindex:"-1"},[n("a",{class:"header-anchor",href:"#背景"},[n("span",null,"背景")])],-1)),n("p",null,[s[1]||(s[1]=a("在 PostgreSQL 的 ",-1)),l(e,{to:"/notes/PostgreSQL/PostgreSQL%20VACUUM.html"},{default:i(()=>[...s[0]||(s[0]=[a("VACUUM",-1)])]),_:1}),s[2]||(s[2]=a(" 流程中，Phase I 的堆表扫描需要把扫描到的死亡元组 TID（页面号 + 页内偏移）收集起来，供后续 Phase II 和 III 的索引清理和堆页面回收使用。在 PostgreSQL 17 之前，这个集合的底层存储是一个排序数组。",-1))]),s[10]||(s[10]=c(`<p>PostgreSQL 17 开始引入 Tid Store 数据结构替代原先的排序数组。Tid Store 底层基于 Leis, V., Kemper, A., Neumann, T. 在 ICDE 2013 上发表的 <em>The Adaptive Radix Tree: ARTful Indexing for Main-Memory Databases</em> 实现的 Adaptive Radix Tree (ART)，不仅将内存占用降低了一到两个数量级，还大幅提升了 TID 查找效率，使 VACUUM 的性能得到了明显改善。</p><p>本文将从 Radix Tree 讲起，分析 ART 的改进思路以及 PostgreSQL 引入 Tid Store 前后的变化。整体上涉及三个提交：</p><ul><li><code>ee1b30f128</code> - Add template for adaptive radix tree.</li><li><code>30e144287a</code> - Add TIDStore, to store sets of TIDs (ItemPointerData) efficiently.</li><li><code>667e65aac3</code> - Use TidStore for dead tuple TIDs storage during lazy vacuum.</li></ul><h2 id="trie-与-radix-tree" tabindex="-1"><a class="header-anchor" href="#trie-与-radix-tree"><span>Trie 与 Radix Tree</span></a></h2><h3 id="trie-前缀树" tabindex="-1"><a class="header-anchor" href="#trie-前缀树"><span>Trie（前缀树）</span></a></h3><p>Trie 是一种用于高效检索序列集合的树形结构。它的特点是：从根到叶的路径本身就编码了键值，查找时间只与键的长度 k 相关，和集合大小 n 无关。不同键的公共前缀共享同一段路径。比如：</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">存储 &quot;data&quot;, &quot;database&quot;, &quot;datastore&quot;, &quot;datum&quot;:</span>
<span class="line"></span>
<span class="line">    (root)</span>
<span class="line">      |</span>
<span class="line">      d</span>
<span class="line">      |</span>
<span class="line">      a</span>
<span class="line">      |</span>
<span class="line">      t</span>
<span class="line">     / \\</span>
<span class="line">    a*   u</span>
<span class="line">   / \\    \\</span>
<span class="line">  b   s    m*</span>
<span class="line">  |   |</span>
<span class="line">  a   t</span>
<span class="line">  |   |</span>
<span class="line">  s   o</span>
<span class="line">  |   |</span>
<span class="line">  e*  r</span>
<span class="line">      |</span>
<span class="line">      e*</span>
<span class="line"></span>
<span class="line">（* 标记有值的节点）</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>整棵 Trie 有 16 个节点。但 Trie 有个问题：如果字符集大小为 σ（比如按一个字节来分层就是 256），每个节点都要维护一个大小为 σ 的指针数组用于存放下层节点。当树的下层比较稀疏的时候，大部分指针都是 NULL，内存浪费将会非常严重。</p><h3 id="radix-tree-基数树" tabindex="-1"><a class="header-anchor" href="#radix-tree-基数树"><span>Radix Tree（基数树）</span></a></h3><p>Radix Tree 是 Trie 的一种空间压缩变体。核心思想是把只有单个子节点的连续边合并成一条边（路径压缩），消除冗余节点。还是上面那个例子，Radix Tree 压缩后只需要 6 个节点：</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">     (root)</span>
<span class="line">       |</span>
<span class="line">      dat</span>
<span class="line">      / \\</span>
<span class="line">    a*   um*</span>
<span class="line">   / \\</span>
<span class="line">base* store*</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>另一个常见的变体是按固定长度的 bit 组（span）进行分支。比如 Linux 内核的 <a href="https://github.com/torvalds/linux/blob/v6.19/include/linux/xarray.h#L1154" target="_blank" rel="noopener noreferrer">XArray</a> 使用 span=6，每个节点有 64 个槽位，每层消费键的 6 个 bit。这种按 span 分层的方式让 Radix Tree 适用于整数键的场景——键被拆成若干个固定宽度的 chunk，每层用一个 chunk 做索引。</p><p>Span 的选择是一个权衡：span 越大，树越矮、查找路径越短，但节点的指针数组越大，稀疏时浪费越严重；span 越小，节点紧凑，但树变高，访问层数增加。</p><p>传统 Radix Tree 的根本矛盾在于：每个内部节点的指针数组大小是 <strong>固定</strong> 的，在构建之前无法预知每个节点实际会有几个子节点。Span 选大了，稀疏节点浪费严重；选小了，稠密节点又要多走层数。无论怎么选，都是在用一个静态策略去应对动态的数据分布。</p><h3 id="典型应用场景" tabindex="-1"><a class="header-anchor" href="#典型应用场景"><span>典型应用场景</span></a></h3><p>Trie / Radix Tree 在系统软件中被广泛使用：</p><ul><li>路由表查找：IP 地址是固定长度的 bit 序列，Radix Tree 做最长前缀匹配</li><li>内存页面管理：Linux 内核的 page cache，键是页面偏移量</li><li>文件系统：目录项索引、inode 映射</li><li>数据库索引：内存数据库的主键索引、字符串字典编码</li></ul><p>共同特点是：键为整数或定长序列，查找频繁，需要有序遍历或范围查询。</p><h2 id="adaptive-radix-tree-art" tabindex="-1"><a class="header-anchor" href="#adaptive-radix-tree-art"><span>Adaptive Radix Tree（ART）</span></a></h2><p>ART 源自 Leis, V., Kemper, A., Neumann, T. 在 ICDE 2013 上发表的论文 <a href="https://db.in.tum.de/~leis/papers/ART.pdf" target="_blank" rel="noopener noreferrer"><em>The Adaptive Radix Tree: ARTful Indexing for Main-Memory Databases</em></a>。它要解决的核心问题是：在保持 Radix Tree 有序性和查找效率的前提下，消除稀疏节点的内存浪费。</p><h3 id="自适应节点类型" tabindex="-1"><a class="header-anchor" href="#自适应节点类型"><span>自适应节点类型</span></a></h3><p>ART 的核心创新是：根据子节点数量 <strong>动态选择</strong> 不同的节点表示。其定义了四种节点类型：</p><table><thead><tr><th>节点类型</th><th>容量上限</th><th>查找方式</th><th>适用场景</th></tr></thead><tbody><tr><td>Node4</td><td>4</td><td>线性扫描 key 数组</td><td>极稀疏</td></tr><tr><td>Node16</td><td>16</td><td>SIMD 并行比较 key 数组</td><td>中低密度</td></tr><tr><td>Node48</td><td>48</td><td>256 项索引 → 紧凑数组</td><td>中高密度</td></tr><tr><td>Node256</td><td>256</td><td>直接索引</td><td>稠密（传统方式）</td></tr></tbody></table><p>当节点的子节点数量超出当前类型容量时，节点升级为下一级别；反之则降级。这使得 ART 在稀疏时接近 Hash Table 的内存效率，在稠密时又保持传统 Radix Tree 的性能。</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">一个内部节点只有 3 个子节点时，使用 Node4：</span>
<span class="line">  Node4 { keys: [0x0A, 0x1F, 0x80, _], children: [ptr1, ptr2, ptr3, _] }</span>
<span class="line"></span>
<span class="line">当第 5 个子节点插入，升级为 Node16：</span>
<span class="line">  Node16 { keys: [0x0A, 0x1F, 0x42, 0x80, 0xCC, _, ...], children: [...] }</span>
<span class="line"></span>
<span class="line">超过 16 个子节点，升级为 Node48：</span>
<span class="line">  Node48 { index[256]: 大部分为空, 有值的字节指向 children 数组的槽位 }</span>
<span class="line"></span>
<span class="line">超过 48 个子节点，升级为 Node256：</span>
<span class="line">  Node256 { children[256]: 直接用字节值做下标索引 }</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="性能特征" tabindex="-1"><a class="header-anchor" href="#性能特征"><span>性能特征</span></a></h3><p>论文的实验表明，ART 在内存数据库工作负载中：</p><ul><li>查找性能接近 Hash Table，优于 B+ 树和传统 Radix Tree</li><li>稀疏键分布下，空间效率远优于固定 span=8 的传统 Radix Tree（后者每个节点 2KB，ART 的 Node4 只要数十字节）</li><li>键天然有序，范围扫描的缓存友好性远优于 Hash Table</li><li>插入/删除的代价是节点类型切换时的拷贝，但分摊后依旧高效</li></ul><h2 id="vacuum-中旧的-dead-tuple-存储" tabindex="-1"><a class="header-anchor" href="#vacuum-中旧的-dead-tuple-存储"><span>VACUUM 中旧的 Dead Tuple 存储</span></a></h2><p>在 Tid Store 引入之前（PostgreSQL 16 及更早），VACUUM 用一个扁平的 <code>ItemPointerData</code> 数组存储死亡元组的 TID。数据结构定义如下：</p><div class="language-c line-numbers-mode" data-highlighter="prismjs" data-ext="c"><pre><code class="language-c"><span class="line"><span class="token keyword">typedef</span> <span class="token keyword">struct</span> <span class="token class-name">VacDeadItems</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">int</span>         max_items<span class="token punctuation">;</span>      <span class="token comment">/* # slots allocated in array */</span></span>
<span class="line">    <span class="token keyword">int</span>         num_items<span class="token punctuation">;</span>      <span class="token comment">/* current # of entries */</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment">/* Sorted array of TIDs to delete from indexes */</span></span>
<span class="line">    ItemPointerData items<span class="token punctuation">[</span>FLEXIBLE_ARRAY_MEMBER<span class="token punctuation">]</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span> VacDeadItems<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token macro property"><span class="token directive-hash">#</span><span class="token directive keyword">define</span> <span class="token macro-name function">MAXDEADITEMS</span><span class="token expression"><span class="token punctuation">(</span>avail_mem<span class="token punctuation">)</span> </span><span class="token punctuation">\\</span></span>
<span class="line">    <span class="token expression"><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token punctuation">(</span>avail_mem<span class="token punctuation">)</span> <span class="token operator">-</span> <span class="token function">offsetof</span><span class="token punctuation">(</span>VacDeadItems<span class="token punctuation">,</span> items<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token operator">/</span> <span class="token keyword">sizeof</span><span class="token punctuation">(</span>ItemPointerData<span class="token punctuation">)</span><span class="token punctuation">)</span></span></span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>每个 <code>ItemPointerData</code> 占 6 字节（4 字节 <code>BlockNumber</code> + 2 字节 <code>OffsetNumber</code>）。这个方案存在几个问题：</p><ul><li>1GB 硬上限：数组内存分配受 <code>MaxAllocSize</code>（1GB）限制，最多只能存放约 1.78 亿条 TID。对死元组较多的表来说可能不够，在放满后不得不中断扫描、先清理索引、清空数组后再继续——而每次中断都意味着重新扫描所有索引，带来极大的 I/O 放大。</li><li>悲观预分配：数组大小在 VACUUM 开始时就根据表大小和 <code>maintenance_work_mem</code> 计算并一次性分配。即使最终只有很少的 dead tuple，内存也已经分配出去了。</li><li>查找效率差：索引清理阶段需要对每个索引条目判断它指向的 heap TID 是否是 dead tuple。对于数千万元素的数组，二分查找在大范围内跳跃，CPU cache miss 率高，分支预测表现糟糕。</li><li>并行 VACUUM 受限：数组放在共享内存中时必须预先确定大小，无法按需扩展。</li></ul><h2 id="postgresql-的-art-实现" tabindex="-1"><a class="header-anchor" href="#postgresql-的-art-实现"><span>PostgreSQL 的 ART 实现</span></a></h2><p>PostgreSQL 的 ART 实现位于 <code>radixtree.h</code>，被设计为 C 宏模板模式。通过在 <code>#include</code> 之前定义一组宏，为特定值类型和内存模型生成特化代码：</p><div class="language-c line-numbers-mode" data-highlighter="prismjs" data-ext="c"><pre><code class="language-c"><span class="line"><span class="token macro property"><span class="token directive-hash">#</span><span class="token directive keyword">define</span> <span class="token macro-name">RT_PREFIX</span>       <span class="token expression">local_ts        </span><span class="token comment">// 符号前缀</span></span></span>
<span class="line"><span class="token macro property"><span class="token directive-hash">#</span><span class="token directive keyword">define</span> <span class="token macro-name">RT_VALUE_TYPE</span>   <span class="token expression">BlocktableEntry </span><span class="token comment">// 值类型</span></span></span>
<span class="line"><span class="token macro property"><span class="token directive-hash">#</span><span class="token directive keyword">define</span> <span class="token macro-name function">RT_VARLEN_VALUE_SIZE</span><span class="token expression"><span class="token punctuation">(</span>page<span class="token punctuation">)</span> </span><span class="token punctuation">\\</span></span>
<span class="line">    <span class="token expression"><span class="token punctuation">(</span><span class="token function">offsetof</span><span class="token punctuation">(</span>BlocktableEntry<span class="token punctuation">,</span> words<span class="token punctuation">)</span> <span class="token operator">+</span> </span><span class="token punctuation">\\</span></span>
<span class="line">    <span class="token expression"><span class="token keyword">sizeof</span><span class="token punctuation">(</span>bitmapword<span class="token punctuation">)</span> <span class="token operator">*</span> <span class="token punctuation">(</span>page<span class="token punctuation">)</span><span class="token operator">-&gt;</span>nwords<span class="token punctuation">)</span></span></span></span>
<span class="line"><span class="token macro property"><span class="token directive-hash">#</span><span class="token directive keyword">include</span> <span class="token string">&quot;lib/radixtree.h&quot;</span></span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="键与-span" tabindex="-1"><a class="header-anchor" href="#键与-span"><span>键与 Span</span></a></h3><p>固定使用 64 位无符号整数键，span 为 8（每层消费一个字节）。PostgreSQL 中实现了非常简易的路径压缩：跳过键高位全为零的层级，树不会因为键空间的理论上限而变得不必要的深。这意味着：</p><ul><li>每层使用键的一个字节来索引，最多 8 层</li><li>Fan-out 最大 256，字节可直接寻址，不需要位运算提取</li><li>树高度随键值范围自适应：如果所有键都小于 2^24，那么树最多只有 3 层</li></ul><h3 id="四种节点" tabindex="-1"><a class="header-anchor" href="#四种节点"><span>四种节点</span></a></h3><div class="language-c line-numbers-mode" data-highlighter="prismjs" data-ext="c"><pre><code class="language-c"><span class="line"><span class="token comment">/* Common header for all nodes */</span></span>
<span class="line"><span class="token keyword">typedef</span> <span class="token keyword">struct</span> <span class="token class-name">RT_NODE</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    uint8       kind<span class="token punctuation">;</span>       <span class="token comment">/* Node kind: 4/16/48/256 */</span></span>
<span class="line">    uint8       fanout<span class="token punctuation">;</span>     <span class="token comment">/* Max capacity for current size class */</span></span>
<span class="line">    uint8       count<span class="token punctuation">;</span>      <span class="token comment">/* Number of children */</span></span>
<span class="line"><span class="token punctuation">}</span>           RT_NODE<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">typedef</span> <span class="token keyword">struct</span> <span class="token class-name">RT_NODE_4</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    RT_NODE     base<span class="token punctuation">;</span></span>
<span class="line">    uint8       chunks<span class="token punctuation">[</span>RT_FANOUT_4_MAX<span class="token punctuation">]</span><span class="token punctuation">;</span></span>
<span class="line">    RT_PTR_ALLOC children<span class="token punctuation">[</span>FLEXIBLE_ARRAY_MEMBER<span class="token punctuation">]</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span>           RT_NODE_4<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">typedef</span> <span class="token keyword">struct</span> <span class="token class-name">RT_NODE_16</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    RT_NODE     base<span class="token punctuation">;</span></span>
<span class="line">    uint8       chunks<span class="token punctuation">[</span>RT_FANOUT_16_MAX<span class="token punctuation">]</span><span class="token punctuation">;</span></span>
<span class="line">    RT_PTR_ALLOC children<span class="token punctuation">[</span>FLEXIBLE_ARRAY_MEMBER<span class="token punctuation">]</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span>           RT_NODE_16<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">typedef</span> <span class="token keyword">struct</span> <span class="token class-name">RT_NODE_48</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    RT_NODE     base<span class="token punctuation">;</span></span>
<span class="line">    uint8       slot_idxs<span class="token punctuation">[</span>RT_NODE_MAX_SLOTS<span class="token punctuation">]</span><span class="token punctuation">;</span>  <span class="token comment">/* 256-element index */</span></span>
<span class="line">    bitmapword  isset<span class="token punctuation">[</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">]</span><span class="token punctuation">;</span></span>
<span class="line">    RT_PTR_ALLOC children<span class="token punctuation">[</span>FLEXIBLE_ARRAY_MEMBER<span class="token punctuation">]</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span>           RT_NODE_48<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">typedef</span> <span class="token keyword">struct</span> <span class="token class-name">RT_NODE_256</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    RT_NODE     base<span class="token punctuation">;</span></span>
<span class="line">    bitmapword  isset<span class="token punctuation">[</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">]</span><span class="token punctuation">;</span></span>
<span class="line">    RT_PTR_ALLOC children<span class="token punctuation">[</span>RT_FANOUT_256<span class="token punctuation">]</span><span class="token punctuation">;</span>      <span class="token comment">/* 256 slots, direct index */</span></span>
<span class="line"><span class="token punctuation">}</span>           RT_NODE_256<span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Node4 和 Node16 把 key chunk 排好序放在 <code>chunks[]</code> 数组中，查找时线性扫描或 SIMD 并行比较。Node48 用一个 256 元素的 <code>slot_idxs</code> 数组做间接索引——给一个 chunk 值，查 <code>slot_idxs[chunk]</code> 得到子节点在 <code>children[]</code> 中的位置。Node256 就是传统方式，chunk 直接作为 <code>children[]</code> 的下标。</p><h3 id="size-class-解耦" tabindex="-1"><a class="header-anchor" href="#size-class-解耦"><span>Size Class 解耦</span></a></h3><p>PostgreSQL 实现的一个创新是将节点 kind 与 size class 解耦。同一个 kind 可以有不同容量。比如 Node16 有两个子类（<code>RT_FANOUT_16_LO</code> 和 <code>RT_FANOUT_16_HI</code>），用于适配 DSA 的固定大小分配块，减少内存碎片：</p><div class="language-c line-numbers-mode" data-highlighter="prismjs" data-ext="c"><pre><code class="language-c"><span class="line"><span class="token macro property"><span class="token directive-hash">#</span><span class="token directive keyword">define</span> <span class="token macro-name">RT_FANOUT_16_LO</span> <span class="token expression"><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token number">160</span> <span class="token operator">-</span> <span class="token function">offsetof</span><span class="token punctuation">(</span>RT_NODE_16<span class="token punctuation">,</span> children<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token operator">/</span> <span class="token keyword">sizeof</span><span class="token punctuation">(</span>RT_PTR_ALLOC<span class="token punctuation">)</span><span class="token punctuation">)</span></span></span></span>
<span class="line"><span class="token macro property"><span class="token directive-hash">#</span><span class="token directive keyword">define</span> <span class="token macro-name">RT_FANOUT_16_HI</span> <span class="token expression"><span class="token function">Min</span><span class="token punctuation">(</span>RT_FANOUT_16_MAX<span class="token punctuation">,</span> <span class="token punctuation">(</span><span class="token number">320</span> <span class="token operator">-</span> <span class="token function">offsetof</span><span class="token punctuation">(</span>RT_NODE_16<span class="token punctuation">,</span> children<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token operator">/</span> <span class="token keyword">sizeof</span><span class="token punctuation">(</span>RT_PTR_ALLOC<span class="token punctuation">)</span><span class="token punctuation">)</span></span></span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="叶节点存储" tabindex="-1"><a class="header-anchor" href="#叶节点存储"><span>叶节点存储</span></a></h3><p>如果值类型的大小不超过指针大小，值直接嵌入最后一层节点的子指针槽位中；否则单独分配内存，槽位存指针。走哪条路径在编译期就已经确定，运行时没有额外的判断开销。</p><h2 id="tid-store-的设计" tabindex="-1"><a class="header-anchor" href="#tid-store-的设计"><span>Tid Store 的设计</span></a></h2><p>Tid Store（<code>tidstore.c</code>）是 ART 在 PostgreSQL 内核中的使用者。它用 Radix Tree 做两级索引：</p><ul><li>Key：<code>BlockNumber</code>（uint32，作为 uint64 使用）</li><li>Value：<code>BlocktableEntry</code>，一个变长的 bitmapword 数组，每个 bit 代表该页面上对应 offset 是否为 dead tuple</li></ul><div class="language-c line-numbers-mode" data-highlighter="prismjs" data-ext="c"><pre><code class="language-c"><span class="line"><span class="token keyword">typedef</span> <span class="token keyword">struct</span> <span class="token class-name">BlocktableEntry</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    uint16      nwords<span class="token punctuation">;</span></span>
<span class="line">    bitmapword  words<span class="token punctuation">[</span>FLEXIBLE_ARRAY_MEMBER<span class="token punctuation">]</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span> BlocktableEntry<span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>逻辑上看，整个结构是这样的：</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">radix tree (key = BlockNumber)</span>
<span class="line">├── 42   → bitmap [offset 3, 7, 15]</span>
<span class="line">├── 100  → bitmap [offset 1, 2]</span>
<span class="line">└── 999  → bitmap [offset 5, 12, 200]</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="插入" tabindex="-1"><a class="header-anchor" href="#插入"><span>插入</span></a></h3><p><code>TidStoreSetBlockOffsets</code> 接收一个 <code>BlockNumber</code> 和一组 <code>OffsetNumber</code>，把 offset 编码成 bitmap 后写入 Radix Tree：</p><div class="language-c line-numbers-mode" data-highlighter="prismjs" data-ext="c"><pre><code class="language-c"><span class="line"><span class="token keyword">void</span></span>
<span class="line"><span class="token function">TidStoreSetBlockOffsets</span><span class="token punctuation">(</span>TidStore <span class="token operator">*</span>ts<span class="token punctuation">,</span> BlockNumber blkno<span class="token punctuation">,</span></span>
<span class="line">                        OffsetNumber <span class="token operator">*</span>offsets<span class="token punctuation">,</span> <span class="token keyword">int</span> num_offsets<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">char</span>        data<span class="token punctuation">[</span>MaxBlocktableEntrySize<span class="token punctuation">]</span><span class="token punctuation">;</span></span>
<span class="line">    BlocktableEntry <span class="token operator">*</span>page <span class="token operator">=</span> <span class="token punctuation">(</span>BlocktableEntry <span class="token operator">*</span><span class="token punctuation">)</span> data<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">for</span> <span class="token punctuation">(</span>wordnum <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span> wordnum <span class="token operator">&lt;=</span> <span class="token function">WORDNUM</span><span class="token punctuation">(</span>offsets<span class="token punctuation">[</span>num_offsets <span class="token operator">-</span> <span class="token number">1</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">;</span> wordnum<span class="token operator">++</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">{</span></span>
<span class="line">        word <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token keyword">while</span> <span class="token punctuation">(</span>idx <span class="token operator">&lt;</span> num_offsets<span class="token punctuation">)</span></span>
<span class="line">        <span class="token punctuation">{</span></span>
<span class="line">            OffsetNumber off <span class="token operator">=</span> offsets<span class="token punctuation">[</span>idx<span class="token punctuation">]</span><span class="token punctuation">;</span></span>
<span class="line">            <span class="token keyword">if</span> <span class="token punctuation">(</span>off <span class="token operator">&gt;=</span> next_word_threshold<span class="token punctuation">)</span></span>
<span class="line">                <span class="token keyword">break</span><span class="token punctuation">;</span></span>
<span class="line">            word <span class="token operator">|=</span> <span class="token punctuation">(</span><span class="token punctuation">(</span>bitmapword<span class="token punctuation">)</span> <span class="token number">1</span> <span class="token operator">&lt;&lt;</span> <span class="token function">BITNUM</span><span class="token punctuation">(</span>off<span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">            idx<span class="token operator">++</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token punctuation">}</span></span>
<span class="line">        page<span class="token operator">-&gt;</span>words<span class="token punctuation">[</span>wordnum<span class="token punctuation">]</span> <span class="token operator">=</span> word<span class="token punctuation">;</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">    page<span class="token operator">-&gt;</span>nwords <span class="token operator">=</span> wordnum<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment">/* Insert into the radix tree */</span></span>
<span class="line">    <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token function">TidStoreIsShared</span><span class="token punctuation">(</span>ts<span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">        <span class="token function">shared_ts_set</span><span class="token punctuation">(</span>ts<span class="token operator">-&gt;</span>tree<span class="token punctuation">.</span>shared<span class="token punctuation">,</span> blkno<span class="token punctuation">,</span> page<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token keyword">else</span></span>
<span class="line">        <span class="token function">local_ts_set</span><span class="token punctuation">(</span>ts<span class="token operator">-&gt;</span>tree<span class="token punctuation">.</span>local<span class="token punctuation">,</span> blkno<span class="token punctuation">,</span> page<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="查找" tabindex="-1"><a class="header-anchor" href="#查找"><span>查找</span></a></h3><p><code>TidStoreIsMember</code> 判断一个 TID 是否在集合中：先用 <code>BlockNumber</code> 在 Radix Tree 中定位叶节点（O(k)，k 为键的字节数），再在 bitmap 中 O(1) 检查 offset bit：</p><div class="language-c line-numbers-mode" data-highlighter="prismjs" data-ext="c"><pre><code class="language-c"><span class="line">bool</span>
<span class="line"><span class="token function">TidStoreIsMember</span><span class="token punctuation">(</span>TidStore <span class="token operator">*</span>ts<span class="token punctuation">,</span> ItemPointer tid<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    BlocktableEntry <span class="token operator">*</span>page<span class="token punctuation">;</span></span>
<span class="line">    BlockNumber blk <span class="token operator">=</span> <span class="token function">ItemPointerGetBlockNumber</span><span class="token punctuation">(</span>tid<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    OffsetNumber off <span class="token operator">=</span> <span class="token function">ItemPointerGetOffsetNumber</span><span class="token punctuation">(</span>tid<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token function">TidStoreIsShared</span><span class="token punctuation">(</span>ts<span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">        page <span class="token operator">=</span> <span class="token function">shared_ts_find</span><span class="token punctuation">(</span>ts<span class="token operator">-&gt;</span>tree<span class="token punctuation">.</span>shared<span class="token punctuation">,</span> blk<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token keyword">else</span></span>
<span class="line">        page <span class="token operator">=</span> <span class="token function">local_ts_find</span><span class="token punctuation">(</span>ts<span class="token operator">-&gt;</span>tree<span class="token punctuation">.</span>local<span class="token punctuation">,</span> blk<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">if</span> <span class="token punctuation">(</span>page <span class="token operator">==</span> <span class="token constant">NULL</span><span class="token punctuation">)</span></span>
<span class="line">        <span class="token keyword">return</span> false<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">int</span> wordnum <span class="token operator">=</span> <span class="token function">WORDNUM</span><span class="token punctuation">(</span>off<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token keyword">int</span> bitnum <span class="token operator">=</span> <span class="token function">BITNUM</span><span class="token punctuation">(</span>off<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">if</span> <span class="token punctuation">(</span>wordnum <span class="token operator">&gt;=</span> page<span class="token operator">-&gt;</span>nwords<span class="token punctuation">)</span></span>
<span class="line">        <span class="token keyword">return</span> false<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">return</span> <span class="token punctuation">(</span>page<span class="token operator">-&gt;</span>words<span class="token punctuation">[</span>wordnum<span class="token punctuation">]</span> <span class="token operator">&amp;</span> <span class="token punctuation">(</span><span class="token punctuation">(</span>bitmapword<span class="token punctuation">)</span> <span class="token number">1</span> <span class="token operator">&lt;&lt;</span> bitnum<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token operator">!=</span> <span class="token number">0</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>相比旧方案的二分查找，这里不存在跨越大段内存的随机跳跃，对分支预测也更加友好。</p><h3 id="共享内存支持" tabindex="-1"><a class="header-anchor" href="#共享内存支持"><span>共享内存支持</span></a></h3><p>通过定义 <code>RT_SHMEM</code> 宏，Radix Tree 创建在 DSA（Dynamic Shared Memory Area）中，多个进程可以并发访问。这是支持并行 VACUUM 的关键：</p><div class="language-c line-numbers-mode" data-highlighter="prismjs" data-ext="c"><pre><code class="language-c"><span class="line"><span class="token macro property"><span class="token directive-hash">#</span><span class="token directive keyword">define</span> <span class="token macro-name">RT_PREFIX</span> <span class="token expression">shared_ts</span></span></span>
<span class="line"><span class="token macro property"><span class="token directive-hash">#</span><span class="token directive keyword">define</span> <span class="token macro-name">RT_SHMEM</span></span></span>
<span class="line"><span class="token macro property"><span class="token directive-hash">#</span><span class="token directive keyword">define</span> <span class="token macro-name">RT_VALUE_TYPE</span> <span class="token expression">BlocktableEntry</span></span></span>
<span class="line"><span class="token macro property"><span class="token directive-hash">#</span><span class="token directive keyword">define</span> <span class="token macro-name function">RT_VARLEN_VALUE_SIZE</span><span class="token expression"><span class="token punctuation">(</span>page<span class="token punctuation">)</span> </span><span class="token punctuation">\\</span></span>
<span class="line">    <span class="token expression"><span class="token punctuation">(</span><span class="token function">offsetof</span><span class="token punctuation">(</span>BlocktableEntry<span class="token punctuation">,</span> words<span class="token punctuation">)</span> <span class="token operator">+</span> </span><span class="token punctuation">\\</span></span>
<span class="line">    <span class="token expression"><span class="token keyword">sizeof</span><span class="token punctuation">(</span>bitmapword<span class="token punctuation">)</span> <span class="token operator">*</span> <span class="token punctuation">(</span>page<span class="token punctuation">)</span><span class="token operator">-&gt;</span>nwords<span class="token punctuation">)</span></span></span></span>
<span class="line"><span class="token macro property"><span class="token directive-hash">#</span><span class="token directive keyword">include</span> <span class="token string">&quot;lib/radixtree.h&quot;</span></span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="vacuum-中的变化" tabindex="-1"><a class="header-anchor" href="#vacuum-中的变化"><span>VACUUM 中的变化</span></a></h2><p>提交 <code>667e65aac3</code> 用 Tid Store 替换了 VACUUM 中的扁平数组。先看关键数据结构的变化：</p><div class="language-c line-numbers-mode" data-highlighter="prismjs" data-ext="c"><pre><code class="language-c"><span class="line"><span class="token comment">/* Before: */</span></span>
<span class="line"><span class="token keyword">typedef</span> <span class="token keyword">struct</span> <span class="token class-name">LVRelState</span> <span class="token punctuation">{</span></span>
<span class="line">    VacDeadItems <span class="token operator">*</span>dead_items<span class="token punctuation">;</span>       <span class="token comment">/* sorted array of dead TIDs */</span></span>
<span class="line">    <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span></span>
<span class="line"><span class="token punctuation">}</span> LVRelState<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">/* After: */</span></span>
<span class="line"><span class="token keyword">typedef</span> <span class="token keyword">struct</span> <span class="token class-name">LVRelState</span> <span class="token punctuation">{</span></span>
<span class="line">    TidStore   <span class="token operator">*</span>dead_items<span class="token punctuation">;</span>         <span class="token comment">/* radix tree backed TID storage */</span></span>
<span class="line">    VacDeadItemsInfo <span class="token operator">*</span>dead_items_info<span class="token punctuation">;</span></span>
<span class="line">    <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span></span>
<span class="line"><span class="token punctuation">}</span> LVRelState<span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>分配方式的变化——不再一次性 <code>palloc</code> 一大块，而是按实际数据量渐进增长：</p><div class="language-c line-numbers-mode" data-highlighter="prismjs" data-ext="c"><pre><code class="language-c"><span class="line"><span class="token comment">/* Before: */</span></span>
<span class="line">dead_items <span class="token operator">=</span> <span class="token punctuation">(</span>VacDeadItems <span class="token operator">*</span><span class="token punctuation">)</span> <span class="token function">palloc</span><span class="token punctuation">(</span><span class="token function">vac_max_items_to_alloc_size</span><span class="token punctuation">(</span>max_items<span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">dead_items<span class="token operator">-&gt;</span>max_items <span class="token operator">=</span> max_items<span class="token punctuation">;</span></span>
<span class="line">dead_items<span class="token operator">-&gt;</span>num_items <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">/* After: */</span></span>
<span class="line">dead_items_info <span class="token operator">=</span> <span class="token punctuation">(</span>VacDeadItemsInfo <span class="token operator">*</span><span class="token punctuation">)</span> <span class="token function">palloc</span><span class="token punctuation">(</span><span class="token keyword">sizeof</span><span class="token punctuation">(</span>VacDeadItemsInfo<span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">dead_items_info<span class="token operator">-&gt;</span>max_bytes <span class="token operator">=</span> vac_work_mem <span class="token operator">*</span> <span class="token number">1024L</span><span class="token punctuation">;</span></span>
<span class="line">dead_items_info<span class="token operator">-&gt;</span>num_items <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span></span>
<span class="line">vacrel<span class="token operator">-&gt;</span>dead_items <span class="token operator">=</span> <span class="token function">TidStoreCreateLocal</span><span class="token punctuation">(</span>dead_items_info<span class="token operator">-&gt;</span>max_bytes<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>收集 dead tuple 的方式也变了。以前是逐个构造 <code>ItemPointerData</code> 然后追加到数组里：</p><div class="language-c line-numbers-mode" data-highlighter="prismjs" data-ext="c"><pre><code class="language-c"><span class="line"><span class="token comment">/* Before: */</span></span>
<span class="line"><span class="token function">ItemPointerSetBlockNumber</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>tmp<span class="token punctuation">,</span> blkno<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">int</span> i <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span> i <span class="token operator">&lt;</span> lpdead_items<span class="token punctuation">;</span> i<span class="token operator">++</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    <span class="token function">ItemPointerSetOffsetNumber</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>tmp<span class="token punctuation">,</span> deadoffsets<span class="token punctuation">[</span>i<span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    dead_items<span class="token operator">-&gt;</span>items<span class="token punctuation">[</span>dead_items<span class="token operator">-&gt;</span>num_items<span class="token operator">++</span><span class="token punctuation">]</span> <span class="token operator">=</span> tmp<span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>现在是按页面批量写入，offset 用 bitmap 压缩：</p><div class="language-c line-numbers-mode" data-highlighter="prismjs" data-ext="c"><pre><code class="language-c"><span class="line"><span class="token comment">/* After: */</span></span>
<span class="line"><span class="token keyword">static</span> <span class="token keyword">void</span></span>
<span class="line"><span class="token function">dead_items_add</span><span class="token punctuation">(</span>LVRelState <span class="token operator">*</span>vacrel<span class="token punctuation">,</span> BlockNumber blkno<span class="token punctuation">,</span></span>
<span class="line">               OffsetNumber <span class="token operator">*</span>offsets<span class="token punctuation">,</span> <span class="token keyword">int</span> num_offsets<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    <span class="token function">TidStoreSetBlockOffsets</span><span class="token punctuation">(</span>vacrel<span class="token operator">-&gt;</span>dead_items<span class="token punctuation">,</span> blkno<span class="token punctuation">,</span> offsets<span class="token punctuation">,</span> num_offsets<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    vacrel<span class="token operator">-&gt;</span>dead_items_info<span class="token operator">-&gt;</span>num_items <span class="token operator">+=</span> num_offsets<span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>判断是否满的逻辑也从&quot;条目数是否达到上限&quot;变成了&quot;内存使用是否超出阈值&quot;：</p><div class="language-c line-numbers-mode" data-highlighter="prismjs" data-ext="c"><pre><code class="language-c"><span class="line"><span class="token comment">/* Before: */</span></span>
<span class="line"><span class="token keyword">if</span> <span class="token punctuation">(</span>dead_items<span class="token operator">-&gt;</span>max_items <span class="token operator">-</span> dead_items<span class="token operator">-&gt;</span>num_items <span class="token operator">&lt;</span> MaxHeapTuplesPerPage<span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">/* After: */</span></span>
<span class="line"><span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token function">TidStoreMemoryUsage</span><span class="token punctuation">(</span>dead_items<span class="token punctuation">)</span> <span class="token operator">&gt;</span> dead_items_info<span class="token operator">-&gt;</span>max_bytes<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>用 Tid Store 替换扁平数组后，前文提到的旧方案的几个问题都得到了解决：</p><ul><li>渐进式内存增长：Radix Tree 按需做小粒度分配，不再受单次 <code>MaxAllocSize</code> 的 1GB 上限限制，也不需要预估表有多少 dead tuple。小表 VACUUM 不会浪费内存。</li><li>内存效率提升一到两个数量级：旧方案每个 TID 占 6 字节，新方案中同一个页面上的所有 dead offset 共享一个 bitmap。</li><li>大幅减少 I/O：大表 VACUUM 因 TID 存储满而中断扫描的场景大幅减少，因此避免了重复全量扫描索引。</li><li>查找速度大幅提升：索引清理阶段对每个 TID 做成员判断时，Radix Tree 的查找路径是固定的（取决于 <code>BlockNumber</code> 的字节数，不随集合大小增长），然后通过 bitmap 做一次 bit 测试。相比于数千万元素上的二分查找，CPU cache 的行为好得多。</li><li>共享内存友好：通过 DSA 后端，并行 VACUUM 的多个 worker 可以共享同一个 Tid Store，且不需要预先确定共享内存大小。</li></ul><p>整体来看，Tid Store 把 dead tuple TID 的存储从 &quot;排序数组 + 二分查找&quot; 替换为 &quot;ART + bitmap&quot;。对日常运维来说最直观的体感是：VACUUM 占用更少的内存，中断清理索引的频率更低，索引清理阶段的 TID 查找更快。</p><h2 id="参考" tabindex="-1"><a class="header-anchor" href="#参考"><span>参考</span></a></h2><ul><li>Leis, V., Kemper, A., Neumann, T. (2013). &quot;The Adaptive Radix Tree: ARTful Indexing for Main-Memory Databases&quot;. <em>ICDE 2013</em>.</li><li>PostgreSQL 源码：<code>radixtree.h</code>、<code>tidstore.c</code></li><li><a href="https://git.postgresql.org/gitweb/?p=postgresql.git;a=commit;h=ee1b30f128d8f63a5184d2bcf1c48a3efc3fcbf9" target="_blank" rel="noopener noreferrer">PostgreSQL commit ee1b30f128</a></li><li><a href="https://git.postgresql.org/gitweb/?p=postgresql.git;a=commit;h=30e144287a72529c9cd9fd6b07fe96eb8a1e270e" target="_blank" rel="noopener noreferrer">PostgreSQL commit 30e144287a</a></li><li><a href="https://git.postgresql.org/gitweb/?p=postgresql.git;a=commit;h=667e65aac354975c6f8090c6146fceb8d7b762d6" target="_blank" rel="noopener noreferrer">PostgreSQL commit 667e65aac3</a></li></ul>`,79))])}const v=p(d,[["render",u]]),b=JSON.parse('{"path":"/notes/PostgreSQL/PostgreSQL%20TidStore.html","title":"PostgreSQL - Tid Store","lang":"en-US","frontmatter":{},"git":{},"filePathRelative":"notes/PostgreSQL/PostgreSQL TidStore.md"}');export{v as comp,b as data};
